20: def doValidation() {
21:   // Run all the tasks associated with `check` except for `test` - the latter is executed via `doTest`
22:   sh """
23:     ./retry_zinc ./gradlew -PscalaVersion=$SCALA_VERSION clean check -x test \
24:         --profile --continue -PxmlSpotBugsReport=true -PkeepAliveMode="session"
25:   """
26: }
27: 
28: def isChangeRequest(env) {
29:   env.CHANGE_ID != null && !env.CHANGE_ID.isEmpty()
30: }
31: 
32: def doTest(env, target = "test") {
33:   sh """./gradlew -PscalaVersion=$SCALA_VERSION ${target} \
34:       --profile --continue -PkeepAliveMode="session" -PtestLoggingEvents=started,passed,skipped,failed \
35:       -PignoreFailures=true -PmaxParallelForks=2 -PmaxTestRetries=1 -PmaxTestRetryFailures=10"""
36:   junit '**/build/test-results/**/TEST-*.xml'
37: }
38: 
39: def runTestOnDevBranch(env) {
40:   if (!isChangeRequest(env)) {
41:     doTest(env)
42:   }
43: }
44: 
45: def doStreamsArchetype() {
46:   echo 'Verify that Kafka Streams archetype compiles'
47: 
48:   sh '''
49:     ./gradlew streams:publishToMavenLocal clients:publishToMavenLocal connect:json:publishToMavenLocal connect:api:publishToMavenLocal \
50:          || { echo 'Could not publish kafka-streams.jar (and dependencies) locally to Maven'; exit 1; }
51:   '''
52: 
53:   VERSION = sh(script: 'grep "^version=" gradle.properties | cut -d= -f 2', returnStdout: true).trim()
54: 
55:   dir('streams/quickstart') {
56:     sh '''
57:       mvn clean install -Dgpg.skip  \
58:           || { echo 'Could not `mvn install` streams quickstart archetype'; exit 1; }
59:     '''
60: 
61:     dir('test-streams-archetype') {
62:       // Note the double quotes for variable interpolation
63:       sh """ 
64:         echo "Y" | mvn archetype:generate \
65:             -DarchetypeCatalog=local \
66:             -DarchetypeGroupId=org.apache.kafka \
67:             -DarchetypeArtifactId=streams-quickstart-java \
68:             -DarchetypeVersion=${VERSION} \
69:             -DgroupId=streams.examples \
70:             -DartifactId=streams.examples \
71:             -Dversion=0.1 \
72:             -Dpackage=myapps \
73:             || { echo 'Could not create new project using streams quickstart archetype'; exit 1; }
74:       """
75: 
76:       dir('streams.examples') {
77:         sh '''
78:           mvn compile \
79:               || { echo 'Could not compile streams quickstart archetype project'; exit 1; }
80:         '''
81:       }
82:     }
83:   }
84: }
85: 
86: def tryStreamsArchetype() {
87:   try {
88:     doStreamsArchetype()
89:   } catch(err) {
90:     echo 'Failed to build Kafka Streams archetype, marking this build UNSTABLE'
91:     currentBuild.result = 'UNSTABLE'
92:   }
93: }
